// Minimal vanilla JS spinner with live status
function createSpinner(container) {
  const wrapper = document.createElement("div");
  wrapper.className = "agent-progress";
  wrapper.innerHTML = `
    <div class="spinner" aria-label="Processing"></div>
    <span class="status-text">Starting…</span>
    <span class="elapsed">0s</span>
  `;
  container.appendChild(wrapper);

  let startTime = Date.now();
  let elapsedTimer = setInterval(() => {
    const s = Math.floor((Date.now() - startTime) / 1000);
    wrapper.querySelector(".elapsed").textContent = `${s}s`;
  }, 1000);

  return {
    setStatus(phase, toolName) {
      const el = wrapper.querySelector(".status-text");
      switch (phase) {
        case "thinking":   el.textContent = "Thinking…"; break;
        case "tool_call":  el.textContent = `Calling ${toolName}…`; break;
        case "streaming":  el.textContent = "Writing response…"; break;
        case "done":
          el.textContent = "Done";
          clearInterval(elapsedTimer);
          break;
      }
    },
    remove() {
      clearInterval(elapsedTimer);
      wrapper.remove();
    },
  };
}

// Wire to SSE progress events
const spinner = createSpinner(document.getElementById("chat"));
eventSource.addEventListener("message", (e) => {
  const ev = JSON.parse(e.data);
  if (ev.type === "progress") {
    spinner.setStatus(ev.phase, ev.current_tool);
  } else if (ev.type === "done") {
    spinner.remove();
  }
});

.agent-progress {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  color: #94a3b8;
  font-family: monospace;
  font-size: 13px;
}

.spinner {
  width: 16px;
  height: 16px;
  border: 2px solid #1e3a5f;
  border-top-color: #3b82f6;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

.elapsed { color: #475569; font-size: 11px; }

// Client: render step dots
function StepIndicator({ current, total, label }) {
  const dots = Array.from({ length: total }, (_, i) => {
    if (i < current - 1) return '<span class="dot done">✓</span>';
    if (i === current - 1) return '<span class="dot active"></span>';
    return '<span class="dot pending"></span>';
  }).join("");

  return `
    <div class="step-indicator">
      <div class="dots">${dots}</div>
      <span class="step-label">Step ${current} of ${total}: ${label}</span>
    </div>
  `;
}

eventSource.addEventListener("message", (e) => {
  const ev = JSON.parse(e.data);
  if (ev.type === "step") {
    document.getElementById("progress").innerHTML =
      StepIndicator({ current: ev.current, total: ev.total, label: ev.item });
  }
});

function updateProgressBar(pct, done, total) {
  const bar = document.querySelector(".progress-fill");
  const label = document.querySelector(".progress-label");
  bar.style.width = `${pct}%`;
  label.textContent = `${done} / ${total} documents (${pct}%)`;
}

eventSource.addEventListener("message", (e) => {
  const ev = JSON.parse(e.data);
  if (ev.type === "progress_bar") {
    updateProgressBar(ev.pct, ev.done, ev.total);
  }
});

function renderContextBar({ used_tokens, limit_tokens, pct, warn }) {
  const bar = document.querySelector(".context-fill");
  const label = document.querySelector(".context-label");
  bar.style.width = `${pct}%`;
  bar.style.backgroundColor = warn ? "#f59e0b" : "#3b82f6";
  label.textContent = `${Math.round(used_tokens / 1000)}k / ${Math.round(limit_tokens / 1000)}k tokens used`;
  if (warn) {
    document.querySelector(".context-warning").textContent =
      "Context is nearly full — consider starting a new conversation.";
  }
}

// Cancel button wires to a DELETE endpoint
document.getElementById("cancel-btn").addEventListener("click", async () => {
  await fetch(`/sessions/${sessionId}/abort`, { method: "POST" });
});
